async (params, browser) => {
  // Open Trello
  await browser.open('https://trello.com')

  // Let Trello load
  await browser.wait(2000)

  // Search via Trello API
  const result = await browser.evaluate(`const resp = await fetch('/1/search?query=' + encodeURIComponent(params.query) + '&cards_limit=15&boards_limit=5&modelTypes=cards,boards', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Search failed: ' + resp.status); const data = await resp.json(); const cards = (data.cards || []).map(c => ({ type: 'card', name: c.name, description: c.desc?.substring(0, 150) || '', board: c.board?.name || '', list: c.list?.name || '', labels: (c.labels || []).map(l => l.name || l.color), due: c.due || '', url: c.shortUrl || c.url })); const boards = (data.boards || []).map(b => ({ type: 'board', name: b.name, description: b.desc?.substring(0, 150) || '', url: b.url || b.shortUrl })); return { query: params.query, cards_found: cards.length, boards_found: boards.length, cards: cards, boards: boards }`)

  return result
}
